import SwiftUI
import AppKit

final class LocalWebServerModel: ObservableObject { @Published var running = false; @Published var message = ""; private var process: Process?; func start(folder: URL, port: String) { guard !running, let number = Int(port) else { message = "Choose a folder and valid port."; return }; let task = Process(); task.executableURL = URL(fileURLWithPath: "/usr/bin/python3"); task.arguments = ["-m", "http.server", "\(number)", "--directory", folder.path]; do { try task.run(); process = task; running = true; message = "Serving http://127.0.0.1:\(number)" } catch { message = error.localizedDescription } }; func stop() { process?.terminate(); process = nil; running = false; message = "Server stopped." } }
struct localwebserverview: View { @StateObject private var model = LocalWebServerModel(); @State private var folder: URL?; @State private var port = "8000"; var body: some View { VStack(alignment: .leading, spacing: 16) { JuicerFeatureHeader(title: "Local Web Server", subtitle: "Serve a selected folder with Python's built-in HTTP server.", icon: "server.rack", refreshing: model.running, action: {}) ; HStack { Button("Choose Folder…") { choose() }; TextField("Port", text: $port).frame(width: 90); Button(model.running ? "Stop" : "Start") { if model.running { model.stop() } else if let folder { model.start(folder: folder, port: port) } }.buttonStyle(.borderedProminent) }; if let folder { Text(folder.path).font(.caption).foregroundStyle(.secondary) }; Text(model.message).font(.caption); Spacer() }.padding(24).onDisappear { model.stop() } }
    private func choose() { let panel = NSOpenPanel(); panel.canChooseDirectories = true; panel.canChooseFiles = false; if panel.runModal() == .OK { folder = panel.url } }
}
